const body = $json.body ?? $json;
const startedAt = Date.now();
return [{ json: {
  traceId: body.traceId || `mcp-${Date.now()}`,
  action: String(body.action || 'unknown'),
  params: typeof body.params === 'object' && body.params !== null ? body.params : {},
  roomId: body.roomId || null,
  deviceId: body.deviceId || null,
  requestedByWorkflowId: body.requestedByWorkflowId || null,
  startedAt
}}];

const input = $json;
const action = input.action;
let status = 200;
let ok = true;
let data = null;
let error = null;

try {
  if (action === 'health.check') {
    data = { service: 'mcp-gateway', status: 'ok' };
  } else if (action === 'echo') {
    data = { echo: input.params };
  } else {
    status = 400;
    ok = false;
    error = { code: 'UNSUPPORTED_ACTION', message: `Unsupported action: ${action}` };
  }
} catch (e) {
  status = 500;
  ok = false;
  error = { code: 'MCP_GATEWAY_FAILURE', message: e.message || String(e) };
}

return [{ json: { ...input, ok, status, data, error } }];

const finishedAt = Date.now();
const durationMs = finishedAt - Number($json.startedAt || finishedAt);
const classification = $json.ok ? 'success' : ($json.status >= 500 ? 'upstream_error' : 'client_error');
return [{ json: {
  ok: Boolean($json.ok),
  status: Number($json.status || 500),
  data: $json.data ?? null,
  error: $json.error ?? null,
  durationMs,
  traceId: $json.traceId,
  roomId: $json.roomId,
  deviceId: $json.deviceId,
  requestedByWorkflowId: $json.requestedByWorkflowId,
  classification,
  source: 'mcp-gateway'
}}];
